import ast
import json

# Load business refs from reviews in 2018
refs = [d['business_ref'] for d in var_call_MB8LUees1cDbnzasq9G58Iki]
ids = set([r.replace('businessref_', 'businessid_') for r in refs])

# Gather documents from available var_call_* variables
found = {}
for name, val in list(globals().items()):
    if not name.startswith('var_call_'):
        continue
    # val should be a list of records
    if isinstance(val, list):
        for rec in val:
            if isinstance(rec, dict) and 'business_id' in rec:
                bid = rec['business_id']
                if bid in ids:
                    found[bid] = rec

# Helper to evaluate truthy BikeParking
def bike_true(v):
    if v is None:
        return False
    if isinstance(v, bool):
        return v
    if isinstance(v, str):
        low = v.lower()
        if 'true' in low:
            return True
        return False
    return False

# Helper to evaluate BusinessParking
def business_parking_true(v):
    if v is None:
        return False
    if isinstance(v, dict):
        for val in v.values():
            if isinstance(val, bool) and val:
                return True
            if isinstance(val, str) and 'true' in val.lower():
                return True
        return False
    if isinstance(v, str):
        s = v.strip()
        if s.lower() == 'none':
            return False
        try:
            parsed = ast.literal_eval(s)
            if isinstance(parsed, dict):
                return business_parking_true(parsed)
            # if parsed is not dict, fallback
        except Exception:
            # try to find 'true' substring
            if 'true' in s.lower():
                return True
            return False
    return False

# Compute count
matching_ids = []
for bid in ids:
    rec = found.get(bid)
    if not rec:
        continue
    attrs = rec.get('attributes')
    if attrs is None:
        continue
    # If attributes is string 'None'
    if isinstance(attrs, str) and attrs.strip().lower() == 'none':
        continue
    # attrs may be dict or string
    if isinstance(attrs, str):
        try:
            attrs = ast.literal_eval(attrs)
        except Exception:
            # cannot parse - skip
            attrs = None
    if not isinstance(attrs, dict):
        continue
    bike = False
    buspark = False
    if 'BikeParking' in attrs:
        bike = bike_true(attrs.get('BikeParking'))
    if 'BusinessParking' in attrs:
        buspark = business_parking_true(attrs.get('BusinessParking'))
    if bike or buspark:
        matching_ids.append(bid)

result = {'count': len(matching_ids), 'business_ids': sorted(matching_ids)}

print("__RESULT__:")
print(json.dumps(result))

